const item = $input.first() || {};
const json = item.json || {};
const body = json.body && typeof json.body === 'object' ? json.body : json;

// Suporte para Evolution v2
let data = body.data || body;
if (Array.isArray(data)) data = data[0];

const event = String(body.event || '').trim().toUpperCase().replace(/[.-]/g, '_');
if (event !== 'MESSAGES_UPSERT') {
  return [{ json: { skip: true, reason: `event_type:${event || 'unknown'}` } }];
}

const key = data?.key || {};
const msgContent = data?.message || {};
const remoteJid = String(key.remoteJid || '').trim();
const fromMe = Boolean(key.fromMe);
const messageId = String(key.id || '').trim();
const sender = String(key.participant || key.remoteJid || '').trim();

// FILTRO DEFINITIVO: Se a mensagem começa com [BOT] e veio de fromMe, IGNORE.
if (fromMe) {
  const rawText = String(
    msgContent.conversation ||
    msgContent.extendedTextMessage?.text ||
    ''
  ).trim();
  if (rawText.startsWith('[BOT]')) {
    return [{ json: { skip: true, reason: 'bot_self_reply' } }];
  }
}

if (!remoteJid.endsWith('@g.us')) return [{ json: { skip: true, reason: 'not_group' } }];

const allowedGroup = String($env.WPP_KB_GROUP_JID || '').trim();
if (allowedGroup && remoteJid !== allowedGroup) {
  return [{ json: { skip: true, reason: `wrong_group:${remoteJid}` } }];
}

// Detect media
const mediaTypes = [
  { key: 'imageMessage', type: 'image' },
  { key: 'documentMessage', type: 'document' },
  { key: 'audioMessage', type: 'audio' },
  { key: 'videoMessage', type: 'video' },
];
let mediaType = '';
let mediaData = null;
for (const mt of mediaTypes) {
  if (msgContent[mt.key]) {
    mediaType = mt.type;
    mediaData = msgContent[mt.key];
    break;
  }
}

const messageText = String(
  (mediaData && mediaData.caption) ||
  msgContent.conversation ||
  msgContent.extendedTextMessage?.text ||
  ''
).trim();

if (!messageText && !mediaType) {
  return [{ json: { skip: true, reason: 'empty' } }];
}

return [{ json: {
  skip: false,
  message_text: messageText,
  sender_jid: sender,
  group_jid: remoteJid,
  message_id: messageId,
  has_media: Boolean(mediaType),
  raw_message: JSON.stringify(key),
} }];
